// Get the first incoming item
const inputData = $input.first().json;

// Return only the body
return [
  {
    json: inputData.body
  }
];

const items = $input.all();

return items.map(item => {

  const rawText = item.json.output || "";

  // Extract Decision
  const decisionMatch = rawText.match(/Decision:\s*(.*)/);
  const decision = decisionMatch ? decisionMatch[1].trim() : null;

  // Extract Agents
  const agentRegex = /Agent Name:\s*(.*?)\n\s*- Purpose:\s*(.*?)\n\s*- Node:\s*(.*?)\n\s*- Reason:\s*(.*?)(?=\n\n|\n\d+\. Agent Name:|$)/gs;

  let agents = [];
  let match;

  while ((match = agentRegex.exec(rawText)) !== null) {
    agents.push({
      name: match[1]?.trim() || "",
      purpose: match[2]?.trim() || "",
      node: match[3]?.trim() || "",
      reason: match[4]?.trim() || "",
    });
  }

  // Extract Workflow Steps
  const stepsRegex = /Step \d+:\s*(.*?)\s*→/g;
  let steps = [];
  let stepMatch;

  while ((stepMatch = stepsRegex.exec(rawText)) !== null) {
    steps.push(stepMatch[1]?.trim() || "");
  }

  return {
    json: {
      decision,
      agents,
      workflow_flow: steps
    }
  };
});

const items = $input.all();

return items.map(item => {

  const data = item.json;

  const decisionClass =
    data.decision === "Multi-Agent Required"
      ? "multi"
      : "simple";

  const agentsHTML = Array.isArray(data.agents)
    ? data.agents.map(agent => `
        <div class="agent-card">
          <div class="agent-name">${agent.name || ""}</div>

          <div class="label">Purpose</div>
          <div>${agent.purpose || ""}</div>

          <div class="label">Node</div>
          <div>${agent.node || ""}</div>

          <div class="label">Reason</div>
          <div>${agent.reason || ""}</div>
        </div>
      `).join("")
    : "";

  const stepsHTML = Array.isArray(data.workflow_flow)
    ? data.workflow_flow.map(step =>
        `<div class="step">${step}</div>`
      ).join("")
    : "";

  const html = `
  <html>
  <head>
    <style>
      body {
        font-family: 'Segoe UI', sans-serif;
        background: #f4f7fb;
        padding: 40px;
      }

      .card {
        background: white;
        border-radius: 18px;
        padding: 28px;
        margin-bottom: 30px;
        box-shadow: 0 15px 40px rgba(0,0,0,0.06);
      }

      .decision {
        font-size: 22px;
        font-weight: 600;
        padding: 14px 22px;
        border-radius: 12px;
        display: inline-block;
      }

      .multi {
        background: linear-gradient(135deg, #e8f5e9, #c8e6c9);
        color: #1b5e20;
      }

      .simple {
        background: linear-gradient(135deg, #fff3e0, #ffe0b2);
        color: #e65100;
      }

      .title {
        font-size: 24px;
        font-weight: 600;
        margin-bottom: 25px;
      }

      .agent-grid {
        display: grid;
        grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
        gap: 22px;
      }

      .agent-card {
        background: #f9fbff;
        border-radius: 16px;
        padding: 22px;
        border: 1px solid #e6ecf5;
        transition: 0.3s ease;
      }

      .agent-card:hover {
        transform: translateY(-6px);
        box-shadow: 0 10px 25px rgba(0,0,0,0.08);
      }

      .agent-name {
        font-size: 18px;
        font-weight: 600;
        margin-bottom: 12px;
        color: #2c3e50;
      }

      .label {
        font-size: 13px;
        font-weight: 600;
        margin-top: 12px;
        color: #7b8ca8;
      }

      .steps {
        display: flex;
        flex-wrap: wrap;
        gap: 14px;
      }

      .step {
        background: #eef3ff;
        padding: 12px 18px;
        border-radius: 30px;
        font-size: 14px;
        color: #3f51b5;
      }
    </style>
  </head>

  <body>

    <div class="card">
      <div class="decision ${decisionClass}">
        ${data.decision || "No Decision"}
      </div>
    </div>

    ${agentsHTML ? `
    <div class="card">
      <div class="title">Agents</div>
      <div class="agent-grid">
        ${agentsHTML}
      </div>
    </div>
    ` : ""}

    ${stepsHTML ? `
    <div class="card">
      <div class="title">Workflow Flow</div>
      <div class="steps">
        ${stepsHTML}
      </div>
    </div>
    ` : ""}

  </body>
  </html>
  `;

  return {
    json: {
      html
    }
  };
});
